// Validate incoming document event payload
const body = $input.first().json.body ?? $input.first().json;
const { document_id, startup_id, doc_type } = body;

const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!document_id || !uuidRe.test(document_id)) {
  return [{ json: { __error: true, status: 400, message: 'Missing or invalid document_id' } }];
}
if (!startup_id || !uuidRe.test(startup_id)) {
  return [{ json: { __error: true, status: 400, message: 'Missing or invalid startup_id' } }];
}
if (!doc_type) {
  return [{ json: { __error: true, status: 400, message: 'Missing doc_type' } }];
}

return [{ json: { document_id, startup_id, doc_type, __error: false } }];

// ── Parse document text ──────────────────────────────────────────────────
// Supports PDF (via pdf-parse) and plain text files.
// For other types, extracts whatever text is available.
const pdfParse = require('pdf-parse');

const fileData = $input.first().binary?.data;
const docInfo = $('Validate Document Event').first().json;

if (!fileData) {
  return [{ json: { __parse_error: true, error_msg: 'No binary data received from storage' } }];
}

const buffer = Buffer.from(fileData, 'base64');
let parsedText = '';

try {
  const parsed = await pdfParse(buffer);
  parsedText = parsed.text;
} catch (e) {
  // Not a PDF — try as UTF-8 text
  try {
    parsedText = buffer.toString('utf-8');
  } catch (e2) {
    return [{ json: {
      __parse_error: true,
      error_msg: `Failed to parse file: ${e.message}`,
      document_id: docInfo.document_id,
      startup_id: docInfo.startup_id,
      doc_type: docInfo.doc_type,
    } }];
  }
}

// Truncate to 80k characters (Claude's safe input limit for a single call)
const MAX_CHARS = 80000;
const truncated = parsedText.length > MAX_CHARS;
const text = parsedText.slice(0, MAX_CHARS);

return [{ json: {
  __parse_error: false,
  document_id: docInfo.document_id,
  startup_id:  docInfo.startup_id,
  doc_type:    docInfo.doc_type,
  parsed_text: text,
  was_truncated: truncated,
  char_count: text.length,
} }];

// ── Build the Claude API prompt ──────────────────────────────────────────
// Batches ALL qualitative metrics relevant to this doc_type into ONE call.
const parseData = $('Parse Document Text').first().json;
const metricsData = $input.first().json;

// All qualitative metrics from the master list
const qualMetrics = (metricsData.all_metrics || []).filter(
  m => m.type === 'qualitative' && m.extraction_prompt
);

if (qualMetrics.length === 0) {
  // No qualitative metrics to score — skip Claude call
  return [{ json: { __skip_claude: true, ...parseData } }];
}

// Build metric rubric block
const metricsBlock = qualMetrics.map((m, i) =>
  `Metric ${i+1}: ${m.name} (slug: ${m.slug})
Rubric: ${m.extraction_prompt}`
).join('\n\n');

// Prompt hash for audit trail (simplified: first 8 chars of combined slugs)
const promptVersion = qualMetrics.map(m => m.slug).sort().join(',').slice(0, 40);

return [{ json: {
  __skip_claude: false,
  document_id:    parseData.document_id,
  startup_id:     parseData.startup_id,
  doc_type:       parseData.doc_type,
  parsed_text:    parseData.parsed_text,
  qual_metrics:   qualMetrics,
  prompt_version: promptVersion,
  claude_prompt: `You are an expert startup analyst scoring metrics for an investment scorecard.
Your task is to score specific metrics for a startup based ONLY on the document excerpt provided.
Do not use external knowledge. If the document does not contain relevant information for a metric, use a score of 0 with model_confidence "low" and note this in the rationale.

Document (${parseData.was_truncated ? 'TRUNCATED TO 80,000 chars' : 'complete'}):
---
${parseData.parsed_text}
---

Metrics to score:
${metricsBlock}

Return ONLY valid JSON, no markdown code blocks, no other text:
{
  "<slug>": {
    "score": <0-10 number>,
    "rationale": "<one to two sentences citing specific text from the document>",
    "model_confidence": "<high|medium|low>"
  },
  ...
}`,
} }];

// ── Parse Claude response and validate JSON ──────────────────────────────
const claudeResponse = $input.first().json;
const buildData = $('Build Claude Extraction Prompt').first().json;

// Handle rate limit (429) or server errors
if (claudeResponse.error) {
  const errType = claudeResponse.error?.type || 'unknown';
  const errMsg  = claudeResponse.error?.message || JSON.stringify(claudeResponse.error);
  return [{ json: {
    __claude_error: true,
    error_msg: `Claude API error (${errType}): ${errMsg}`,
    document_id: buildData.document_id,
    startup_id: buildData.startup_id,
  } }];
}

const rawText = claudeResponse.content?.[0]?.text ?? '';
let parsed;
try {
  // Strip any accidental markdown code fences
  const cleaned = rawText.replace(/^```json\s*/m, '').replace(/^```\s*/m, '').replace(/```$/m, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: {
    __claude_error: true,
    error_msg: `Failed to parse Claude JSON response: ${e.message}. Raw: ${rawText.slice(0, 500)}`,
    document_id: buildData.document_id,
    startup_id: buildData.startup_id,
  } }];
}

// Build upsert payloads for each scored metric
const qualMetrics = buildData.qual_metrics;
const upsertPayloads = [];

for (const metric of qualMetrics) {
  const scored = parsed[metric.slug];
  if (!scored) continue;

  const score = typeof scored.score === 'number'
    ? Math.min(Math.max(scored.score, 0), 10)
    : 0;

  upsertPayloads.push({
    startup_id:         buildData.startup_id,
    metric_id:          metric.id,
    value:              String(score),
    score:              score,
    confidence_tag:     'llm_inferred',
    source_document_id: buildData.document_id,
    llm_rationale:      scored.rationale ?? '',
    model_confidence:   ['high','medium','low'].includes(scored.model_confidence)
                          ? scored.model_confidence : 'low',
    llm_prompt_version: buildData.prompt_version,
  });
}

return [{ json: {
  __claude_error: false,
  startup_id: buildData.startup_id,
  document_id: buildData.document_id,
  upsert_payloads: upsertPayloads,
  scored_count: upsertPayloads.length,
} }];

// ── Upsert all scored metric_values ──────────────────────────────────────
const parseData = $input.first().json;
const payloads = parseData.upsert_payloads;
const ZOORA_API_URL = $env.ZOORA_API_URL;
const SERVICE_KEY = $env.SERVICE_API_KEY;

const results = [];
const errors = [];

for (const payload of payloads) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST',
      url: `${ZOORA_API_URL}/api/metric-values/upsert`,
      headers: { 'x-service-api-key': SERVICE_KEY, 'content-type': 'application/json' },
      body: JSON.stringify(payload),
    });
    results.push(JSON.parse(resp));
  } catch (e) {
    errors.push({ metric_id: payload.metric_id, error: e.message });
  }
}

return [{ json: {
  startup_id: parseData.startup_id,
  upserted: results.length,
  errors: errors,
  document_id: parseData.document_id,
} }];
